17	  // For pure base premium tests we use multi-step or rely on the integration example math.
18	  // Simpler: test the single-item quote with newcomer 0 years, no curse, low enchantment.
19	
20	  // We'll test via runScenario (the top-level entry point).
21	  it("quote a plain sword for newcomer (0 yrs, 1st contract) → 100 base + 10 first ins + 5 fee = 115 G", () => {
22	    const result = runScenario({
23	      customer: { yearsWithMHPCO: 0 },
24	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
