35	
36	  // Block discount
37	  it.todo("3 runes form a block → 60 base premium (block applies)");
38	  it.todo("4 runes → 100 base premium (no block — block requires exactly 3)");
39	  it.todo("7 runes → 175 base premium (one block of 3 = 60, plus 4 individual = 100)");
40	
41	  // Alike-components clarification
42	  it.todo("2 runes + 1 moonstone → 75 base premium (no block: different types)");
43	  it.todo("3 runes + 3 moonstones → 120 base premium (two separate blocks)");
44	
45	  // Modifier thresholds
46	  it.todo("customer with exactly 2 years gets loyalty discount");
47	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
48	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
49	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
50	
51	  // Modifier scope on multi-item policies
52	  it.todo("policy with cursed sword + plain amulet → curse surcharge applies only to sword's base (210 G before fee)");
53	
54	  // Rounding in MHPCO's favor
55	  it.todo("premium 197.5 G → rounded up to 198 G");
56	  it.todo("payout 350.5 G → rounded down to 350 G");
57	
58	  // Integration: Newcomer with a cursed sword
59	  it.todo("newcomer with cursed sword (steel, enchantment 3) → 165 G");
60	
61	  // Integration: Long-standing customer's second contract
62	  it.todo("3-yr customer's 2nd contract, cursed sword enchantment 7 → 160 G");
63	
64	  // Claim processing — standard reimbursement
65	  it.todo("regular sword, damage 500 G → payout 400 G (full minus 100 deductible)");
66	  it.todo("rune damage 200 G → payout 100 G (no special clause, minus deductible)");
67	
68	  // Claim — high enchantment clause
69	  it.todo("steel sword enchantment 9, damage 1000 G → payout 400 G (50% then deductible)");
70	
71	  // Claim — dragon material
72	  it.todo("dragon-material sword enchantment 5, damage 800 G → payout 700 G (full, then deductible)");
73	
74	  // Claim — both clauses (enchantment wins precedence-ordered with 50% then deductible)
75	  it.todo("dragon-material sword enchantment 9, damage 1000 G → payout 400 G");
76	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G → payout 400 G");
77	
78	  // Claim — deductible per damage event (per item)
79	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (100 deductible per item)");
80	
81	  // Multiple items of same type
82	  it.todo("policy covers 2 swords → insurance sum 2000, cap 4000");
83	  it.todo("two swords policy, damages list two sword entries → each treated as separate damage with own deductible");
84	  it.todo("damages has more entries of a type than insured → CLI rejects (non-zero exit)");
85	
86	  // Cap exhaustion
87	  it.todo("sword+amulet policy → insurance sum 1600 G, cap 3200 G");
88	  it.todo("cursed sword → cap based on unmodified insurance value (2000 G)");
89	  it.todo("sword + 3 runes (block) → insurance sum 1750 G (block discount doesn't affect insurance sum)");
90	  it.todo("successive claims on sword (cap 2000): first 1500→pay 1400 cap 600, second 1500→pay 600 cap 0");
91	
92	  // CLI error handling (these are exercised via the CLI, but logic can return errors)
93	  it.todo("quote with unknown item type → CLI exits non-zero with stderr error");
94	  it.todo("claim references damage for item not in policy → CLI exits non-zero");
95	  it.todo("claim damage with negative amount → CLI exits non-zero");
