const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;
const FIRST_INSURANCE_SURCHARGE = 10;

type Step = { op: "quote"; items: Array<unknown> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Step>;
};

const quotePremium = (step: Step): number => {
  if (step.items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE_PREMIUM + FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
};

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  const results = steps.map((step) => ({ premium: quotePremium(step) }));
  return { results };
};
